```java
Object mockDocument = mock(Class.forName("com.google.gson.metrics.ParseBenchmark$Document"));
Object mockApi = mock(Class.forName("com.google.gson.metrics.ParseBenchmark$Api"));
Object mockParser = mock(Class.forName("com.google.gson.metrics.ParseBenchmark$Parser"));
